'use strict';

/* ─────────────────────────────────────
   CHARACTER ANIMATION
───────────────────────────────────── */
const CHAR_IMG_STAND = 'data:image/png;base64,';
const CHAR_IMG_MOW   = 'data:image/png;base64,';

const charAnim = {
  pos: 80,        // % from left
  dir: -1,        // -1=left(default), 1=right
  mowed: 0,       // 0-100%
  frameId: null,
  flipped: false,

  init() {
    const img = qs('#cf-img');
    if (img) img.src = CHAR_IMG_STAND;
    this.reset();
  },

  reset() {
    this.pos    = 80;
    this.dir    = -1;
    this.mowed  = 0;
    this.flipped = false;
    this._applyPos();
    this._setMowed(0);
    const charEl = qs('#cf-char');
    if (charEl) {
      charEl.className = 'cf-char standing';
    }
    const img = qs('#cf-img');
    if (img) img.src = CHAR_IMG_STAND;
    // パーティクル削除
    const pc = qs('#cf-particles');
    if (pc) pc.innerHTML = '';
  },

  start() {
    const img = qs('#cf-img');
    if (img) img.src = CHAR_IMG_MOW;
    const charEl = qs('#cf-char');
    if (charEl) charEl.className = 'cf-char walking' + (this.flipped ? ' flipped' : '');
    this._loop();
  },

  pause() {
    if (this.frameId) { cancelAnimationFrame(this.frameId); this.frameId = null; }
    const img = qs('#cf-img');
    if (img) img.src = CHAR_IMG_STAND;
    const charEl = qs('#cf-char');
    if (charEl) charEl.className = 'cf-char standing' + (this.flipped ? ' flipped' : '');
  },

  stop() {
    if (this.frameId) { cancelAnimationFrame(this.frameId); this.frameId = null; }
    const img = qs('#cf-img');
    if (img) img.src = CHAR_IMG_STAND;
    const charEl = qs('#cf-char');
    if (charEl) charEl.className = 'cf-char standing';
  },

  _loop() {
    const SPEED = 0.18;
    const tick = () => {
      this.pos += this.dir * SPEED;
      if (this.pos <= 8) {
        this.pos = 8; this.dir = 1; this.flipped = true;  // 右向きにflip
      } else if (this.pos >= 92) {
        this.pos = 92; this.dir = -1; this.flipped = false; // 左向き（元画像の向き）
      }
      // flip更新
      const charEl = qs('#cf-char');
      if (charEl) {
        charEl.className = 'cf-char walking' + (this.flipped ? ' flipped' : '');
      }
      this._applyPos();
      // 刈り取り面積（キャラが進んだ右側を刈り跡に）
      const newMowed = Math.max(this.mowed, 100 - this.pos - 10);
      if (newMowed > this.mowed) {
        this.mowed = Math.min(newMowed, 90);
        this._setMowed(this.mowed);
        if (Math.random() < 0.25) this._spawnParticle();
      }
      if (state.working && !state.paused) {
        this.frameId = requestAnimationFrame(tick);
      }
    };
    this.frameId = requestAnimationFrame(tick);
  },

  _applyPos() {
    const charEl   = qs('#cf-char');
    const shadowEl = qs('#cf-shadow');
    if (charEl)   charEl.style.left   = this.pos + '%';
    if (shadowEl) shadowEl.style.left = this.pos + '%';
  },

  _setMowed(pct) {
    const el = qs('#cf-mowed');
    if (el) el.style.width = pct + '%';
  },

  _spawnParticle() {
    const pc = qs('#cf-particles');
    if (!pc) return;
    const p = document.createElement('div');
    p.className = 'cf-particle';
    p.style.left    = (this.pos + (Math.random()-0.5)*8) + '%';
    p.style.bottom  = (49 + Math.random()*6) + '%';
    p.style.height  = (4 + Math.random()*5) + 'px';
    p.style.background = ['#5aaa20','#7acc30','#4a9018','#88cc38'][Math.floor(Math.random()*4)];
    p.style.transform  = 'rotate(' + ((Math.random()-.5)*50) + 'deg)';
    p.style.opacity    = '0.85';
    pc.appendChild(p);
    let op = 0.85;
    const fade = setInterval(() => {
      op -= 0.07;
      p.style.opacity = String(op);
      if (op <= 0) { clearInterval(fade); p.remove(); }
    }, 30);
  },
};


/* ─────────────────────────────────────
   DATA LAYER（Firebase移行を想定した抽象化）
───────────────────────────────────── */
const DB = {
  _key: k => `kt_${k}`,
  get(k)    { try { return JSON.parse(localStorage.getItem(this._key(k))); } catch { return null; } },
  set(k, v) { localStorage.setItem(this._key(k), JSON.stringify(v)); },
  records()       { return this.get('records') || []; },
  saveRecord(r)   { const a = this.records(); a.unshift(r); this.set('records', a); },
  deleteRecord(id){ this.set('records', this.records().filter(r => r.id !== id)); },
  profile()       { return this.get('profile') || { name: 'ユーザー', weight: 60, defaultEquip: 'kari', defaultSpider: 'SP851' }; },
  saveProfile(p)  { this.set('profile', p); },
  spots()         { return this.get('spots') || DEFAULT_SPOTS; },
  saveSpots(s)    { this.set('spots', s); },
  badges()        { return this.get('badges') || []; },
  saveBadges(b)   { this.set('badges', b); },
};

