/* ─────────────────────────────────────
   FIREBASE AUTH
───────────────────────────────────── */
async function signInGoogle() {
  const fb = window._fb;
  if (!fb) { showToast('Firebase未設定です'); return; }
  try {
    const result = await fb.signInWithPopup(fb.auth, fb.provider);
    // onAuthStateChangeで処理されるのでここでは何もしない
  } catch (e) {
    if (e.code !== 'auth/popup-closed-by-user') {
      console.error(e);
      showToast('ログインに失敗しました');
    }
  }
}

async function signOutGoogle() {
  const fb = window._fb;
  if (!fb) return;
  if (!confirm('ログアウトしますか？')) return;
  await fb.signOut(fb.auth);
  showToast('ログアウトしました');
  updateAuthUI();
}

function onAuthStateChange(user) {
  updateAuthUI();
  if (user) {
    // デモ画面表示中ならホームへ移動
    if (state.screen === 'demo') {
      localStorage.setItem('kt_demo_shown', '1');
      stopDemoAnim();
      navigate('home');
      showToast(`✓ ログインしました：${user.displayName}`);
    }
    // ニックネームが未設定ならGoogle表示名を初期値に
    const p = DB.profile();
    if (!p.nickname) {
      p.nickname = user.displayName || '';
      DB.saveProfile(p);
      const nick = qs('#setting-nickname');
      if (nick) nick.value = p.nickname;
    }
  }
}

function updateAuthUI() {
  const user = window._fbUser;
  const loggedOut = qs('#auth-logged-out');
  const loggedIn  = qs('#auth-logged-in');
  if (!loggedOut || !loggedIn) return;
  if (user) {
    loggedOut.classList.add('hidden');
    loggedIn.classList.remove('hidden');
    const nameEl  = qs('#auth-user-name');
    const emailEl = qs('#auth-user-email');
    if (nameEl)  nameEl.textContent  = user.displayName || 'ユーザー';
    if (emailEl) emailEl.textContent = user.email || '';
  } else {
    loggedOut.classList.remove('hidden');
    loggedIn.classList.add('hidden');
  }
}

async function syncNicknameToFirestore(nickname) {
  const fb   = window._fb;
  const user = window._fbUser;
  if (!fb || !user) return;
  try {
    await fb.setDoc(
      fb.doc(fb.db, 'users', user.uid),
      { nickname, updatedAt: fb.serverTimestamp() },
      { merge: true }
    );
  } catch (e) { console.warn('nickname sync failed', e); }
}

/* ─────────────────────────────────────
   RANKING
───────────────────────────────────── */
function renderRanking() {
  const now = new Date();
  const todayStr = dateStr(now);
  const el = qs('#ranking-date');
  if (el) el.textContent = `${now.getFullYear()}年${now.getMonth()+1}月${now.getDate()}日`;

  // ログイン状態によってバナー切替
  const user = window._fbUser;
  const banner   = qs('#login-banner');
  const myCard   = qs('#my-rank-card');
  if (banner) banner.classList.toggle('hidden', !!user);

  // 今日の自分の最高記録を表示
  if (user) {
    const todayRecs = DB.records().filter(r => r.date === todayStr);
    const best = todayRecs.sort((a,b) => b.area - a.area)[0];
    if (best && myCard) {
      myCard.classList.remove('hidden');
      const p = DB.profile();
      const h = Math.floor(best.workDuration/3600), m = Math.floor((best.workDuration%3600)/60);
      qs('#my-rank-name').textContent  = p.nickname || user.displayName || 'あなた';
      qs('#my-rank-stats').textContent = `${(best.area/100).toFixed(1)}a ／ ${h>0?`${h}時間${m}分`:`${m}分`} ／ ${best.calories}kcal`;
      qs('#my-rank-pos').textContent   = '—';
      // 公開済みか確認
      checkPublished(best);
    } else if (myCard) {
      myCard.classList.add('hidden');
    }
  } else if (myCard) {
    myCard.classList.add('hidden');
  }

  loadRanking();
}

async function loadRanking() {
  const fb = window._fb;
  const listEl    = qs('#ranking-list');
  const countEl   = qs('#ranking-count');
  if (!listEl) return;

  listEl.innerHTML = `<div class="ranking-loading"><div class="loading-spinner"></div><div style="font-size:13px;color:var(--text-muted);margin-top:8px">読み込み中…</div></div>`;

  // Firebaseが未設定の場合
  if (!fb || !window._fb?.db) {
    listEl.innerHTML = `<div class="ranking-empty">⚙️ Firebase未設定のため表示できません<br><small>設定ファイルにFirebase設定値を入力してください</small></div>`;
    return;
  }

  try {
    const todayStr = dateStr(new Date());
    const q = fb.query(
      fb.collection(fb.db, 'rankings'),
      fb.where('date', '==', todayStr),
      fb.where('public', '==', true),
      fb.orderBy('area', 'desc'),
      fb.limit(50)
    );
    const snap = await fb.getDocs(q);
    const docs = [];
    snap.forEach(d => docs.push({ id: d.id, ...d.data() }));

    if (countEl) countEl.textContent = `${docs.length}件`;

    if (docs.length === 0) {
      listEl.innerHTML = `<div class="ranking-empty">🌿 今日はまだ記録がありません<br>最初の一刈りを登録しよう！</div>`;
      return;
    }

    const myUid = window._fbUser?.uid;
    listEl.innerHTML = docs.map((r, i) => {
      const pos   = i + 1;
      const isMe  = r.uid === myUid;
      const medal = pos === 1 ? '🥇' : pos === 2 ? '🥈' : pos === 3 ? '🥉' : null;
      const posClass = pos === 1 ? 'gold' : pos === 2 ? 'silver' : pos === 3 ? 'bronze' : '';
      const te    = TERRAIN[r.terrain] || TERRAIN.flat;
      const eq    = EQUIP[r.equipment] || EQUIP.other;
      const h = Math.floor(r.duration/3600), m = Math.floor((r.duration%3600)/60);
      const timeStr = h > 0 ? `${h}時間${m}分` : `${m}分`;
      const areaA = (r.area/100).toFixed(1);

      return `<div class="ranking-item${isMe ? ' is-me' : ''}">
        ${medal
          ? `<div class="rank-medal">${medal}</div>`
          : `<div class="rank-pos ${posClass}">${pos}</div>`}
        <div class="rank-body">
          <div class="rank-name">${escHtml(r.nickname || '名無し')}${isMe ? ' 👈' : ''}</div>
          <div class="rank-meta">
            <span>${te.icon}${te.label}</span>
            <span>${eq.label}</span>
            <span>⏱ ${timeStr}</span>
            ${r.spotName ? `<span>📍${escHtml(r.spotName)}</span>` : ''}
          </div>
        </div>
        <div class="rank-area">
          <div class="rank-area-val">${areaA}</div>
          <div class="rank-area-unit">a</div>
        </div>
      </div>`;
    }).join('');

    // 自分の順位を更新
    if (myUid) {
      const myPos = docs.findIndex(r => r.uid === myUid) + 1;
      const posEl = qs('#my-rank-pos');
      if (posEl && myPos > 0) posEl.textContent = myPos;
    }

  } catch (e) {
    console.error(e);
    listEl.innerHTML = `<div class="ranking-empty">⚠️ 読み込みに失敗しました<br><small>${e.message}</small></div>`;
  }
}

async function checkPublished(record) {
  const fb   = window._fb;
  const user = window._fbUser;
  const btn  = qs('#btn-publish');
  if (!fb || !user || !btn) return;
  try {
    const docRef = fb.doc(fb.db, 'rankings', `${user.uid}_${record.date}`);
    const snap   = await fb.getDoc(docRef);
    if (snap.exists()) {
      btn.textContent = '✓ 公開済み';
      btn.classList.add('published');
      btn.disabled = true;
    }
  } catch { /* silent */ }
}

async function publishTodayRecord() {
  const fb   = window._fb;
  const user = window._fbUser;
  if (!fb || !user) { showToast('ログインが必要です'); return; }

  const todayStr  = dateStr(new Date());
  const todayRecs = DB.records().filter(r => r.date === todayStr);
  const best      = todayRecs.sort((a,b) => b.area - a.area)[0];
  if (!best) { showToast('今日の記録がありません'); return; }

  const p        = DB.profile();
  const nickname = p.nickname || user.displayName || '名無し';
  const btn      = qs('#btn-publish');
  if (btn) { btn.textContent = '送信中…'; btn.disabled = true; }

  try {
    const docId  = `${user.uid}_${todayStr}`;
    const docRef = fb.doc(fb.db, 'rankings', docId);
    await fb.setDoc(docRef, {
      uid:       user.uid,
      nickname,
      date:      todayStr,
      area:      best.area,
      duration:  best.workDuration,
      calories:  best.calories,
      terrain:   best.terrain,
      equipment: best.equipment,
      spotName:  best.spotName || '',
      public:    true,
      publishedAt: fb.serverTimestamp(),
    });
    showToast('🌐 ランキングに公開しました！');
    if (btn) { btn.textContent = '✓ 公開済み'; btn.classList.add('published'); }
    loadRanking();
  } catch (e) {
    console.error(e);
    showToast('公開に失敗しました: ' + e.message);
    if (btn) { btn.textContent = '🌐 公開する'; btn.disabled = false; }
  }
}

/* ─────────────────────────────────────
   FEEDBACK
───────────────────────────────────── */
let fbCat  = 'idea';
let fbStar = 0;

function selectFbCat(cat) {
  fbCat = cat;
  document.querySelectorAll('.fb-cat-btn').forEach(b =>
    b.classList.toggle('selected', b.dataset.cat === cat)
  );
}

function selectFbStar(v) {
  fbStar = v;
  document.querySelectorAll('.fb-star').forEach(s => {
    const sv = parseInt(s.dataset.v);
    s.textContent = sv <= v ? '★' : '☆';
  });
}

async function submitFeedback() {
  const fb  = window._fb;
  const text = qs('#fb-text')?.value.trim() || '';
  const btn  = qs('#fb-submit-btn');

  if (!text) { showToast('内容を入力してください'); return; }

  const user    = window._fbUser;
  const profile = DB.profile();

  if (btn) { btn.textContent = '送信中…'; btn.disabled = true; }

  const payload = {
    category:  fbCat,
    rating:    fbStar,
    text,
    nickname:  profile.nickname || (user?.displayName) || '匿名',
    uid:       user?.uid || null,
    appVersion:'1.0',
    userAgent: navigator.userAgent,
    createdAt: fb ? fb.serverTimestamp() : new Date().toISOString(),
    records:   DB.records().length,   // 参考情報：使用状況
  };

  try {
    if (fb?.db) {
      // Firestoreに保存
      await fb.addDoc(fb.collection(fb.db, 'feedbacks'), payload);
    } else {
      // Firebase未接続時はlocalStorageに一時保存
      const saved = JSON.parse(localStorage.getItem('kt_feedbacks') || '[]');
      saved.push({ ...payload, createdAt: new Date().toISOString() });
      localStorage.setItem('kt_feedbacks', JSON.stringify(saved));
    }

    // 送信成功
    showToast('✓ フィードバックを送信しました！ありがとうございます 🌿');
    if (qs('#fb-text'))  qs('#fb-text').value = '';
    fbStar = 0;
    fbCat  = 'idea';
    selectFbCat('idea');
    document.querySelectorAll('.fb-star').forEach(s => s.textContent = '☆');
    if (btn) { btn.textContent = '📨 送信する / Send'; btn.disabled = false; }

  } catch (e) {
    console.error(e);
    showToast('送信に失敗しました: ' + e.message);
    if (btn) { btn.textContent = '📨 送信する / Send'; btn.disabled = false; }
  }
}

function clearAllData() {
  if (!confirm('すべてのデータを削除しますか？\nThis will delete ALL records. Are you sure?')) return;
  ['records','profile','spots','badges'].forEach(k => localStorage.removeItem(`kt_${k}`));
  showToast('データを削除しました');
  navigate('home');
}

/* ─────────────────────────────────────
   RECORD / SPOT DETAIL (simple modal)
───────────────────────────────────── */
function showRecordDetail(id) {
  const r = DB.records().find(rec => rec.id === id);
  if (!r) return;
  const te = TERRAIN[r.terrain] || TERRAIN.flat;
  const eq = EQUIP[r.equipment] || EQUIP.other;
  const h = Math.floor(r.workDuration/3600), m = Math.floor((r.workDuration%3600)/60);
  const tStr = h > 0 ? `${h}時間${m}分` : `${m}分`;
  qs('#detail-modal-content').innerHTML = `
    <div class="modal-title">${escHtml(r.spotName||'作業記録')}</div>
    <div style="color:rgba(255,255,255,.5);font-size:12px;margin-bottom:14px">${r.date}</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:16px">
      <div class="metric-card"><div class="metric-val">${tStr}</div><div class="metric-lbl">作業時間</div></div>
      <div class="metric-card"><div class="metric-val">${(r.area/100).toFixed(1)}a</div><div class="metric-lbl">刈取面積</div></div>
      <div class="metric-card"><div class="metric-val">${r.calories}</div><div class="metric-unit">kcal</div><div class="metric-lbl">消費カロリー</div></div>
      <div class="metric-card"><div class="metric-val">${r.temperature??'—'}</div><div class="metric-unit">${r.temperature!==null?'℃':''}</div><div class="metric-lbl">気温</div></div>
    </div>
    <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:16px">
      <span class="tag tag-orange">${te.icon} ${te.label} ${te.stars}</span>
      <span class="tag tag-green">${eq.label}</span>
      ${r.gpsEnabled?`<span class="tag tag-sky">GPS ${(r.gpsDist/1000).toFixed(2)}km</span>`:''}
      ${r.weather?`<span class="tag tag-gray">${r.weather}</span>`:''}
    </div>
    ${r.badges.length > 0 ? `<div style="margin-bottom:14px">${r.badges.map(id=>{const b=BADGES_DEF.find(x=>x.id===id);return b?`<span class="badge-chip new">${b.label}</span>`:''}).join(' ')}</div>` : ''}
    <button class="btn-danger-full" onclick="deleteRecord('${r.id}')">🗑 この記録を削除</button>
  `;
  qs('#modal-detail').classList.add('open');
}

function deleteRecord(id) {
  if (!confirm('この記録を削除しますか？')) return;
  DB.deleteRecord(id);
  qs('#modal-detail').classList.remove('open');
  showToast('削除しました');
  if (state.screen === 'home') renderHome();
  if (state.screen === 'records') renderRecords();
}

function showSpotDetail(id) {
  const spot = DB.spots().find(s => s.id === id);
  if (!spot) return;
  const records = DB.records().filter(r => r.spotId === id);
  const totalArea = records.reduce((a,r) => a + r.area, 0);

  const hasLoc = spot.lat && spot.lon;
  const locLabel = hasLoc
    ? `📍 ${spot.lat.toFixed(5)}, ${spot.lon.toFixed(5)}`
    : '📍 位置情報未登録';
  const locColor = hasLoc ? 'var(--lime)' : 'rgba(255,255,255,.35)';

  qs('#detail-modal-content').innerHTML = `
    <div class="modal-title">${escHtml(spot.name)}</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px">
      <div class="metric-card"><div class="metric-val">${records.length}</div><div class="metric-lbl">作業回数</div></div>
      <div class="metric-card"><div class="metric-val">${(totalArea/100).toFixed(0)}a</div><div class="metric-lbl">累計面積</div></div>
    </div>
    <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px">
      <span class="tag tag-orange">${TERRAIN[spot.terrain]?.label || '—'}</span>
      <span class="tag tag-gray">目標 年${spot.targetFreq}回</span>
      <span class="tag tag-gray" style="color:${locColor}">${locLabel}</span>
    </div>

    <!-- 位置情報更新ボタン -->
    <button onclick="updateSpotLocation('${id}')" id="btn-update-loc"
      style="width:100%;height:42px;background:rgba(158,232,64,.09);border:1px solid rgba(158,232,64,.28);border-radius:12px;color:var(--neon);font-size:13px;font-weight:700;display:flex;align-items:center;justify-content:center;gap:7px;cursor:pointer;margin-bottom:10px;transition:.2s">
      <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="12" cy="12" r="3"/><path d="M12 2v3M12 19v3M2 12h3M19 12h3"/></svg>
      ${hasLoc ? '📍 位置情報を現在地に更新' : '📍 現在地を位置情報として登録'}
    </button>
    <div id="spot-loc-status" style="font-size:11px;color:rgba(255,255,255,.38);text-align:center;margin-bottom:12px;min-height:14px"></div>

    ${records.length > 0 ? `<div style="font-size:10px;font-weight:700;letter-spacing:.1em;color:rgba(255,255,255,.32);text-transform:uppercase;margin-bottom:8px">最近の作業</div>` : ''}
    ${records.slice(0,3).map(r => recordCardHTML(r)).join('')}
  `;
  qs('#modal-detail').classList.add('open');
}

async function updateSpotLocation(spotId) {
  const btn = qs('#btn-update-loc');
  const status = qs('#spot-loc-status');
  if (!btn || !status) return;

  btn.innerHTML = '📡 位置情報を取得中…';
  btn.style.opacity = '.6';

  try {
    const pos = await getPosition();
    const { latitude: lat, longitude: lon, accuracy } = pos.coords;

    // DBのスポットを更新
    const spots = DB.spots();
    const sp = spots.find(s => s.id === spotId);
    if (sp) {
      sp.lat = lat;
      sp.lon = lon;
      DB.saveSpots(spots);
    }

    btn.innerHTML = `<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> ✅ 位置情報を更新しました`;
    btn.style.background = 'rgba(158,232,64,.2)';
    btn.style.borderColor = 'rgba(158,232,64,.6)';
    btn.style.opacity = '1';
    status.textContent = `緯度 ${lat.toFixed(5)} / 経度 ${lon.toFixed(5)} ／ 精度 ±${Math.round(accuracy)}m`;
    status.style.color = 'var(--lime)';

    // 地図に反映
    if (state.screen === 'map') drawMowedPolygons();
    showToast(`📍 「${sp?.name || 'スポット'}」の位置情報を更新しました`);

  } catch (e) {
    btn.innerHTML = '⚠️ 位置情報の取得に失敗';
    btn.style.opacity = '1';
    btn.style.borderColor = 'rgba(217,79,42,.4)';
    btn.style.color = 'var(--danger)';
    status.textContent = '設定 → プライバシー → 位置情報サービスを確認してください';
  }
}

/* ─────────────────────────────────────
   UTILITIES
───────────────────────────────────── */
function qs(sel, ctx = document) { return ctx.querySelector(sel); }
function qsa(sel, ctx = document) { return [...ctx.querySelectorAll(sel)]; }
function escHtml(s) { return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
function dateStr(d) { return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`; }

let toastTimeout = null;
function showToast(msg) {
  const el = qs('#toast');
  el.textContent = msg;
  el.classList.add('show');
  if (toastTimeout) clearTimeout(toastTimeout);
  toastTimeout = setTimeout(() => el.classList.remove('show'), 3000);
}

/* ─────────────────────────────────────
   INIT
───────────────────────────────────── */
document.addEventListener('DOMContentLoaded', () => {
  // PWA
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('./sw.js').catch(() => {});
  }

  // キャラクター初期化
  charAnim.init();

  // バックグラウンドから復帰時：セッション自動復元
  document.addEventListener('visibilitychange', () => {
    if (document.visibilityState === 'visible' && state.working) {
      // 復帰時に経過時間を再計算
      const now = new Date();
      state.elapsedSec = Math.max(0,
        Math.floor((now - state.startTime - state.totalPaused) / 1000));
      updateTimerDisplay();
      updateWorkMetrics();
      // タイマーが止まっていたら再起動
      if (!state.paused && !timerInterval) startTimerLoop();
    }
  });

  // セッション復帰チェック後、デモ画面かホームへ
  if (!restoreSessionIfNeeded()) {
    // Firebase認証状態はonAuthStateChangedで非同期確認されるため
    // 少し待ってからチェック（Firebaseの初期化を待つ）
    setTimeout(() => {
      if (state.screen === 'demo') {
        // まだデモ画面にいる → authが確定していない状態
        // fbUserがなければそのままデモ表示継続
      }
    }, 800);
    // まずデモ画面チェック（ログイン済みならhome、初回ならdemo）
    checkShowDemo();
  } else {
    const resume = confirm(
      '前回の作業が途中です。\n作業を再開しますか？\n\n' +
      `経過時間: ${Math.floor(state.elapsedSec/60)}分${state.elapsedSec%60}秒`
    );
    if (resume) {
      navigate('work');
      renderWorkScreen();
      charAnim.reset();
      if (!state.paused) {
        charAnim.start();
        startTimerLoop();
      } else {
        charAnim.pause();
        qs('#btn-pause').innerHTML = '▶ 再開';
      }
      startGPS();
      showToast('✓ 作業を再開しました');
    } else {
      // 破棄
      localStorage.removeItem('kt_session');
      state.working = false;
    }
  }

  // Nav
  qsa('.nav-btn').forEach(btn => {
    btn.addEventListener('click', () => navigate(btn.dataset.screen));
  });

  // Start modal
  qs('#btn-start-work').addEventListener('click', openStartModal);
  qs('#modal-start-close').addEventListener('click', closeStartModal);
  qs('#modal-start').addEventListener('click', e => { if (e.target === qs('#modal-start')) closeStartModal(); });

  // Detail modal close
  qs('#modal-detail-close').addEventListener('click', () => qs('#modal-detail').classList.remove('open'));
  qs('#modal-detail').addEventListener('click', e => { if (e.target === qs('#modal-detail')) qs('#modal-detail').classList.remove('open'); });

  // Equip buttons in modal
  qsa('.equip-btn').forEach(b => b.addEventListener('click', () => selectEquip(b.dataset.equip)));
  qsa('.blade-btn').forEach(b => b.addEventListener('click', () => selectBlade(b.dataset.blade)));
  qsa('.modal-terrain-btn').forEach(b => b.addEventListener('click', () => selectModalTerrain(b.dataset.terrain)));

  // Work controls
  qs('#btn-pause').addEventListener('click', togglePause);
  qs('#btn-end').addEventListener('click', endWork);

  // Share
  qs('#btn-share-x').addEventListener('click', shareToX);
  qs('#btn-copy-share').addEventListener('click', copyShareText);

  // Settings
  qs('#btn-save-settings').addEventListener('click', saveSettings);
  qs('#btn-clear-data').addEventListener('click', clearAllData);

  // CSV
  qs('#btn-export-csv').addEventListener('click', exportCSV);

  // Add spot button（地図画面から削除のためコメントアウト）
  // qs('#btn-add-spot')?.addEventListener('click', () => openStartModal());

  // Initial render
  navigate('home');
});
